class Solution {
public:
    int hardestWorker(int n, vector<vector<int>>& logs) {
        int maxTime = 0, maxId = n;
        int prevTime = 0;
        for (auto& log : logs) {
            int id = log[0], time = log[1];
            int duration = time - prevTime;
            if (duration > maxTime || (duration == maxTime && id < maxId)) {
                maxTime = duration;
                maxId = id;
            }
            prevTime = time;
        }
        return maxId;
    }
};
